mapper.select:
SELECT  FROM sys_notification a

	${dataScope}

		AND a.notice_title  LIKE concat('%',#{noticeTitle},'%')


		AND a.preview_content  LIKE concat('%',#{previewContent},'%')


		AND a.force_popup = #{forcePopup}


		AND a.start_time > #{startTime}


		AND a.end_time < #{endTime}


		AND EXISTS (
			SELECT 1
			FROM t_member m
			WHERE m.idno LIKE concat('%', #{targetUserIdno}, '%')
			  AND a.target_user_ids IS NOT NULL
			  AND a.target_user_ids != ''
			  AND JSON_CONTAINS(CAST(a.target_user_ids AS JSON), JSON_QUOTE(m.id))
		)





		ORDER BY ${page.orderBy}


		ORDER BY a.create_time DESC

mapper.insert:
INSERT INTO sys_notification (
	id, notice_title, content_url,content, status, image_url,
	start_time, end_time, notice_type, interval_number, interval_unit, number, force_popup, target_user_ids, preview_content
) VALUES (
	 #{id}, #{noticeTitle}, #{contentUrl},#{content}, #{status}, #{imageUrl},
	 #{startTime}, #{endTime}, #{noticeType}, #{intervalNumber}, #{intervalUnit}, #{number}, #{forcePopup}, #{targetUserIds}, #{previewContent}
)

mapper.update:
UPDATE sys_notification SET
	notice_title=#{noticeTitle}, content_url=#{contentUrl},content=#{content}, status=#{status}, image_url=#{imageUrl},
	start_time=#{startTime}, end_time=#{endTime}, notice_type=#{noticeType}, interval_number=#{intervalNumber}, interval_unit=#{intervalUnit}, number=#{number},
	update_time=#{updateDate},force_popup=#{forcePopup}, target_user_ids=#{targetUserIds}, preview_content=#{previewContent}
WHERE id=#{id}
